import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as n,c as h,a as e,d as a,b as t,f as i}from"./app-7cfa41e7.js";const c={},s=i(`<h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h2><h2 id="嵌入式系统的基本概念" tabindex="-1"><a class="header-anchor" href="#嵌入式系统的基本概念" aria-hidden="true">#</a> 嵌入式系统的基本概念</h2><ul><li>嵌入式系统是以应用为中心和以计算机技术为基础的,并且软硬件是可裁剪的,能满足应用系统对功能,可靠性,成本,体积,功耗等指标的严格要求的专用计算系统</li></ul><h2 id="嵌入式操作系统的基本功能" tabindex="-1"><a class="header-anchor" href="#嵌入式操作系统的基本功能" aria-hidden="true">#</a> 嵌入式操作系统的基本功能</h2><ol><li>处理器的控制与管理</li><li>存储器的分配与管理</li><li>外部设备的控制和管理</li><li>文件的控制和管理</li><li>作业的控制和管理</li></ol><h2 id="嵌入式软件基本结构以及功能" tabindex="-1"><a class="header-anchor" href="#嵌入式软件基本结构以及功能" aria-hidden="true">#</a> 嵌入式软件基本结构以及功能</h2><h3 id="_1-设备驱动层" tabindex="-1"><a class="header-anchor" href="#_1-设备驱动层" aria-hidden="true">#</a> 1. 设备驱动层</h3><p>设备驱动层是必不可少的重要部分,使用任何外部设备都需要有相应的驱动程序的支持,它为上层软件提供饿了设备的操作接口。</p><p>驱动层一般包括:</p><ol><li>硬件抽象层 <ul><li>在于将硬件抽象化,是操作系统内核与硬件电路之间的接口层。</li></ul></li><li>板级支持包 <ul><li>系统启动时,完成对硬件的初始化</li><li>为驱动程序提供访问硬件的手段</li></ul></li><li>设备驱动程序 <ul><li>为上层软件提供设备操作的接口</li></ul></li></ol><h3 id="_2-实时操作系统rtos" tabindex="-1"><a class="header-anchor" href="#_2-实时操作系统rtos" aria-hidden="true">#</a> 2. 实时操作系统RTOS</h3><p>嵌入式系统通常运行在特定的操作系统上，称为实时操作系统。</p><p>RTOS提供任务调度,资源管理,中断处理和通信功能,以确保系统的实时性和可靠性</p><h3 id="_3-中间件" tabindex="-1"><a class="header-anchor" href="#_3-中间件" aria-hidden="true">#</a> 3. 中间件</h3><p>中间件屏蔽了底层操作系统的复杂性,使程序开发人员面对一个简单而统一的开发环境,降低程序设计的复杂性,将注意力集中在自己的业务上,不必再为陈旭在不同的系统软件上的移植而重复工作。中间件可以看作是一个API实现的软件层。</p><h3 id="_4-实际应用程序层" tabindex="-1"><a class="header-anchor" href="#_4-实际应用程序层" aria-hidden="true">#</a> 4. 实际应用程序层</h3><p>应用程序是嵌入式系统中实现具体的功能模块，他们根据系统需求设计和开发，执行特定任务或提供特定的服务。</p><h3 id="基于linux的嵌入式软件" tabindex="-1"><a class="header-anchor" href="#基于linux的嵌入式软件" aria-hidden="true">#</a> 基于Linux的嵌入式软件</h3><ol><li>BootLoader</li><li>内核</li><li>应用程序</li></ol><h2 id="linux文件系统" tabindex="-1"><a class="header-anchor" href="#linux文件系统" aria-hidden="true">#</a> Linux文件系统</h2><h3 id="linux目录结构" tabindex="-1"><a class="header-anchor" href="#linux目录结构" aria-hidden="true">#</a> Linux目录结构:</h3><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/image-20230619202839042.png" alt="Linux目录结构" tabindex="0" loading="lazy"><figcaption>Linux目录结构</figcaption></figure><ol><li>/bin: bin是二进制的缩写,存放Linux常用操作命令的执行文件,如mv,ls,mkdir等</li><li>/boot:存放操作系统启动时所需要的程序,如启动grub就会用到/boot/grub子目录</li><li>/dev:包含所有Linux系统中使用的外部设备,实际上是一个访问这些外部设备的端口</li><li>/etc:存放了系统管理时要用到的各种配置文件和子目录,如网络配置文件,文件系统,设备配置信息和设置用户信息等</li><li>/etc/rc.d 存放Linux启动和关闭时候要用的脚本</li><li>/etc/rc.d/init:新版为/etc/xinetd.d目录,存放所有Linux服务默认的启动脚本</li><li>/home:Linux系统重默认的用户工具根目录</li><li>/lib:存放系统动态链接共享库的.</li><li>/media：光驱和软驱的挂载点</li></ol><h3 id="文件类型和文件属性" tabindex="-1"><a class="header-anchor" href="#文件类型和文件属性" aria-hidden="true">#</a> 文件类型和文件属性</h3><h4 id="_1-普通文件" tabindex="-1"><a class="header-anchor" href="#_1-普通文件" aria-hidden="true">#</a> 1. 普通文件</h4><h4 id="_2-目录文件" tabindex="-1"><a class="header-anchor" href="#_2-目录文件" aria-hidden="true">#</a> 2. 目录文件</h4><h4 id="_3-链接文件" tabindex="-1"><a class="header-anchor" href="#_3-链接文件" aria-hidden="true">#</a> 3. 链接文件</h4><h4 id="_4-设备文件" tabindex="-1"><a class="header-anchor" href="#_4-设备文件" aria-hidden="true">#</a> 4. 设备文件</h4><h4 id="文件属性" tabindex="-1"><a class="header-anchor" href="#文件属性" aria-hidden="true">#</a> 文件属性:</h4><h2 id="linux常用命令" tabindex="-1"><a class="header-anchor" href="#linux常用命令" aria-hidden="true">#</a> Linux常用命令</h2><h3 id="四个阶段" tabindex="-1"><a class="header-anchor" href="#四个阶段" aria-hidden="true">#</a> 四个阶段:</h3><table><thead><tr><th>gcc/g++指令选项</th><th>功 能</th></tr></thead><tbody><tr><td>-E（大写）</td><td>预处理指定的源文件，不进行编译。</td></tr><tr><td>-S（大写）</td><td>编译指定的源文件，但是不进行汇编。</td></tr><tr><td>-c</td><td>编译、汇编指定的源文件，但是不进行链接。</td></tr><tr><td>-o</td><td>指定生成文件的文件名。</td></tr><tr><td>-llibrary（-I library）</td><td>其中 library 表示要搜索的库文件的名称。该选项用于手动指定链接环节中程序可以调用的库文件。建议 -l 和库文件名之间不使用空格，比如 -lstdc++。</td></tr><tr><td>-ansi</td><td>对于 C 语言程序来说，其等价于 -std=c90；对于 C++ 程序来说，其等价于 -std=c++98。</td></tr><tr><td>-std=</td><td>手动指令编程语言所遵循的标准，例如 c89、c90、c++98、c++11 等。</td></tr></tbody></table><ol><li><p>预处理</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>gcc -E hello.c -o hello.i
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>编译</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>gcc -S hello.i -o hello.s
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>汇编</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>gcc -c hello.s -o hello.o
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>链接</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>gcc hello.o -o hello
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li></ol><h3 id="在linux上运行编写的c代码" tabindex="-1"><a class="header-anchor" href="#在linux上运行编写的c代码" aria-hidden="true">#</a> 在Linux上运行编写的c代码:</h3><div class="language-c++ line-numbers-mode" data-ext="c++"><pre class="language-c++"><code>#include &lt;stdio.h&gt;
int main()
{
   // printf() 中字符串需要引号
   printf(&quot;Hello, World!&quot;);
   return 0;
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/image-20230621184029399.png" alt="image-20230621184029399" tabindex="0" loading="lazy"><figcaption>image-20230621184029399</figcaption></figure><h3 id="静态库和动态库" tabindex="-1"><a class="header-anchor" href="#静态库和动态库" aria-hidden="true">#</a> 静态库和动态库</h3>`,37),o=e("li",null,"静态库：是一系列的目标文件(.o文件)的归档文件,文件格式为(libname.a),如果在编译某个程序时链接静态库,则链接器将会搜索静态库,从中提取出它所需要的目标文件并直接拷贝到该程序的可执行二进制文件(ELF格式文件)之中",-1),u={href:"http://xn--libname-e73kr8ckwzxp3ayhqq7h.so",target:"_blank",rel:"noopener noreferrer"},b=i('<h2 id="makefile" tabindex="-1"><a class="header-anchor" href="#makefile" aria-hidden="true">#</a> Makefile</h2><h2 id="文件" tabindex="-1"><a class="header-anchor" href="#文件" aria-hidden="true">#</a> 文件</h2><h3 id="文件描述符的概念" tabindex="-1"><a class="header-anchor" href="#文件描述符的概念" aria-hidden="true">#</a> 文件描述符的概念</h3><ul><li>一个非负整数,一个索引值,并指向内核中每个进程打开的文件记录表</li><li>所有对设备和文件的操作都使用文件描述符进行的</li></ul><p>一个进程启动时,会打开三个文件,标准输入,标准输出和标准出错处理，这3个文件分别对应的文件描述符为0,1,2</p><h3 id="基本i-o操作和标准i-o操作" tabindex="-1"><a class="header-anchor" href="#基本i-o操作和标准i-o操作" aria-hidden="true">#</a> 基本I/O操作和标准I/O操作</h3><h2 id="串口通信" tabindex="-1"><a class="header-anchor" href="#串口通信" aria-hidden="true">#</a> 串口通信</h2><h3 id="_1-设置串口属性" tabindex="-1"><a class="header-anchor" href="#_1-设置串口属性" aria-hidden="true">#</a> 1.设置串口属性</h3><h3 id="_2-打开串口" tabindex="-1"><a class="header-anchor" href="#_2-打开串口" aria-hidden="true">#</a> 2. 打开串口</h3><h3 id="_3-从串口读写数据" tabindex="-1"><a class="header-anchor" href="#_3-从串口读写数据" aria-hidden="true">#</a> 3. 从串口读写数据</h3><h3 id="_4-关闭串口" tabindex="-1"><a class="header-anchor" href="#_4-关闭串口" aria-hidden="true">#</a> 4. 关闭串口</h3><h2 id="进程" tabindex="-1"><a class="header-anchor" href="#进程" aria-hidden="true">#</a> 进程</h2><h3 id="进程间的通信机制" tabindex="-1"><a class="header-anchor" href="#进程间的通信机制" aria-hidden="true">#</a> 进程间的通信机制</h3><h4 id="_1-管道及有名管道" tabindex="-1"><a class="header-anchor" href="#_1-管道及有名管道" aria-hidden="true">#</a> 1. 管道及有名管道</h4><h4 id="_2-信号通信" tabindex="-1"><a class="header-anchor" href="#_2-信号通信" aria-hidden="true">#</a> 2. 信号通信</h4><h4 id="_3-信号量" tabindex="-1"><a class="header-anchor" href="#_3-信号量" aria-hidden="true">#</a> 3. 信号量:</h4><p><strong>1.</strong> **semget()：**创建信号量或获得在系统已存在的信号量。不同</p><p>进程通过使用同一个信号量键值来获得同一个信号量。</p><p>**2. ** **semctl()：**初始化信号量。当使用二维信号量时，通常将信</p><p>号量初始化为1。</p><p><strong>3.</strong> **semop()：**进行信号量的PV操作。</p><p><strong>4.</strong> **semclt()**删除不需要信号量。</p><h4 id="_4-共享内存" tabindex="-1"><a class="header-anchor" href="#_4-共享内存" aria-hidden="true">#</a> 4. 共享内存</h4><h4 id="_5-消息队列" tabindex="-1"><a class="header-anchor" href="#_5-消息队列" aria-hidden="true">#</a> 5. 消息队列</h4><h2 id="网络编程" tabindex="-1"><a class="header-anchor" href="#网络编程" aria-hidden="true">#</a> 网络编程</h2><h3 id="socket概念" tabindex="-1"><a class="header-anchor" href="#socket概念" aria-hidden="true">#</a> socket概念</h3><ul><li>socket是一种特殊的I/O接口,它也是一种文件描述符。是一种常用的进程间通信机制</li><li>一个完整的套接字则用一个相关描述{协议,本地地址,本地端口、远程地址、远程端口}来表示</li><li>socket类似文件的概念,打开、连接建立、数据传输</li></ul><p>TCP流程:</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/image-20230622171035713.png" alt="image-20230622171035713" tabindex="0" loading="lazy"><figcaption>image-20230622171035713</figcaption></figure><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/image-20230622171449371.png" alt="程序" tabindex="0" loading="lazy"><figcaption>程序</figcaption></figure><h2 id="linux设备驱动" tabindex="-1"><a class="header-anchor" href="#linux设备驱动" aria-hidden="true">#</a> Linux设备驱动</h2><h3 id="驱动程序分类" tabindex="-1"><a class="header-anchor" href="#驱动程序分类" aria-hidden="true">#</a> 驱动程序分类:</h3><ol><li>字符设备</li><li>块设备</li><li>网络设备</li></ol><h3 id="层次结构" tabindex="-1"><a class="header-anchor" href="#层次结构" aria-hidden="true">#</a> 层次结构</h3><ol><li>硬件层（Hardware Layer）： <ul><li>硬件层是最底层的驱动程序层次，与物理硬件设备直接交互。</li><li>硬件层的驱动程序负责对具体硬件设备的控制和操作。</li></ul></li><li>总线层（Bus Layer）： <ul><li>总线层提供了对硬件总线的抽象和管理，负责连接和控制硬件设备。</li><li>总线层的驱动程序用于管理特定类型的总线，如PCI总线、USB总线等。</li></ul></li><li>核心层（Core Layer）： <ul><li>核心层提供了通用的驱动框架和设备模型，用于管理和操作设备驱动程序。</li><li>核心层的驱动程序实现设备注册、资源管理、设备访问接口等功能。</li></ul></li><li>子系统层（Subsystem Layer）： <ul><li>子系统层是在核心层之上的一组功能相关的驱动程序组合，用于管理特定类型的设备或子系统。</li><li>子系统层包括网络子系统、块设备子系统、字符设备子系统等。</li></ul></li><li>用户空间层（User Space Layer）： <ul><li>用户空间层包含运行在用户空间的驱动程序，通过系统调用和用户态库与内核进行通信。</li><li>用户空间驱动程序提供对设备的高级操作和服务，以及与应用程序的交互接口。</li></ul></li></ol><h3 id="设备驱动开发流程" tabindex="-1"><a class="header-anchor" href="#设备驱动开发流程" aria-hidden="true">#</a> 设备驱动开发流程</h3><ol><li>编写驱动源码</li><li>编写Makefile文件</li><li>编译驱动模块</li><li>加载驱动模块</li></ol><h2 id="nfs搭建" tabindex="-1"><a class="header-anchor" href="#nfs搭建" aria-hidden="true">#</a> NFS搭建</h2><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/451089beaf3229ec0ce9791b466ace5.png" alt="451089beaf3229ec0ce9791b466ace5" tabindex="0" loading="lazy"><figcaption>451089beaf3229ec0ce9791b466ace5</figcaption></figure><h2 id="交叉编译" tabindex="-1"><a class="header-anchor" href="#交叉编译" aria-hidden="true">#</a> 交叉编译</h2><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/632314974024dee219aa4e3876b26b3.png" alt="632314974024dee219aa4e3876b26b3" tabindex="0" loading="lazy"><figcaption>632314974024dee219aa4e3876b26b3</figcaption></figure>',41);function x(g,f){const d=l("ExternalLinkIcon");return n(),h("div",null,[s,e("ol",null,[o,e("li",null,[a("动态库("),e("a",u,[a("文件名格式为libname.so"),t(d)]),a("):在程序编译时并不会被链接到目标代码中,而是在程序运行时才被载入")])]),b])}const _=r(c,[["render",x],["__file","1.html.vue"]]);export{_ as default};
